mapper.update:
 		UPDATE
				BOARD_FILE
		   SET
				FILE_PATH = #{filePath}
			 ,	ORIGINAL_NAME = #{originalName}
		 WHERE
				BOARD_NO = #{boardNo}
		   AND
				FILE_ORDER = #{fileOrder}

 		UPDATE
				NOTICE_FILE
		   SET
				FILE_PATH = #{filePath}
			 ,	ORIGINAL_NAME = #{originalName}
		 WHERE
				NOTICE_NO = #{noticeNo}
		   AND
				FILE_ORDER = #{fileOrder}
